pre.write_text('from __future__ import annotations\n\nfrom dataclasses import asdict, dataclass, field\nfrom io import BytesIO\nimport os\nfrom pathlib import Path\nfrom typing import Any\n\ntry:\n    import cv2\n    import numpy as np\nexcept Exception:\n    cv2 = None\n    np = None\n\ntry:\n    from PIL import Image\nexcept Exception:\n    Image = None\n\ntry:\n    from rembg import remove as rembg_remove\nexcept Exception:\n    rembg_remove = None\n\n\nIMAGE_SUFFIXES = {".jpg", ".jpeg", ".png", ".webp", ".bmp"}\nMIN_DOCUMENT_AREA_RATIO = 0.04\nALPHA_THRESHOLD = 12\n\n\n@dataclass\nclass ReceiptImagePreprocessingDecision:\n    preprocessing_step: str\n    selected_route: str\n    applied_steps: list[str]\n    fallback_reason: list[str]\n    perspective_normalization: dict[str, Any] | None\n    diagnostics: dict[str, Any] = field(default_factory=dict)\n\n    def to_dict(self) -> dict[str, Any]:\n        return asdict(self)\n\n\ndef _debug_dir() -> Path | None:\n    value = os.environ.get("REZZERV_RECEIPT_PREPROCESS_DEBUG_DIR")\n    if not value:\n        return None\n    path = Path(value)\n    path.mkdir(parents=True, exist_ok=True)\n    return path\n\n\ndef _checkpoint(name: str, diagnostics: dict[str, Any], **values: Any) -> None:\n    diagnostics.setdefault("checkpoints", []).append({"name": name, **values})\n\n\ndef _save_debug_pil(name: str, image: Image.Image | None, diagnostics: dict[str, Any]) -> None:\n    if image is None:\n        return\n    out = _debug_dir()\n    if out is None:\n        return\n    path = out / name\n    image.save(path)\n    diagnostics.setdefault("debug_files", []).append(str(path))\n\n\ndef _save_debug_cv(name: str, image, diagnostics: dict[str, Any]) -> None:\n    if cv2 is None or image is None:\n        return\n    out = _debug_dir()\n    if out is None:\n        return\n    path = out / name\n    cv2.imwrite(str(path), image)\n    diagnostics.setdefault("debug_files", []).append(str(path))\n\n\ndef _decode_image(file_bytes: bytes):\n    if cv2 is None or np is None:\n        return None\n    data = np.frombuffer(file_bytes, dtype=np.uint8)\n    return cv2.imdecode(data, cv2.IMREAD_COLOR)\n\n\ndef _encode_image_png(image) -> bytes | None:\n    if cv2 is None:\n        return None\n    ok, encoded = cv2.imencode(".png", image)\n    return bytes(encoded.tobytes()) if ok else None\n\n\ndef _pil_rgb_to_bgr(image):\n    if cv2 is None or np is None:\n        return None\n    rgb = image.convert("RGB")\n    return cv2.cvtColor(np.array(rgb), cv2.COLOR_RGB2BGR)\n\n\ndef _image_difference_ratio(original, candidate) -> float | None:\n    if cv2 is None or np is None or original is None or candidate is None:\n        return None\n    try:\n        h = min(original.shape[0], candidate.shape[0])\n        w = min(original.shape[1], candidate.shape[1])\n        if h <= 0 or w <= 0:\n            return None\n        a = cv2.resize(original, (w, h))\n        b = cv2.resize(candidate, (w, h))\n        diff = cv2.absdiff(a, b)\n        return float(np.mean(diff) / 255.0)\n    except Exception:\n        return None\n\n\ndef _remove_background_with_rembg(file_bytes: bytes, diagnostics: dict[str, Any]):\n    _checkpoint(\n        "rembg_start",\n        diagnostics,\n        rembg_available=rembg_remove is not None,\n        pillow_available=Image is not None,\n        cv2_available=cv2 is not None,\n        numpy_available=np is not None,\n    )\n\n    if rembg_remove is None:\n        return None, "rembg_unavailable"\n    if Image is None:\n        return None, "pillow_unavailable"\n    if cv2 is None or np is None:\n        return None, "cv2_or_numpy_unavailable"\n\n    try:\n        original_pil = Image.open(BytesIO(file_bytes)).convert("RGB")\n        _save_debug_pil("00_input_original.png", original_pil, diagnostics)\n\n        rgba_bytes = rembg_remove(file_bytes)\n        rgba = Image.open(BytesIO(rgba_bytes)).convert("RGBA")\n    except Exception as exc:\n        _checkpoint("rembg_exception", diagnostics, exception_type=type(exc).__name__, exception=str(exc))\n        return None, f"rembg_failed:{type(exc).__name__}"\n\n    alpha = np.array(rgba.getchannel("A"))\n    ys, xs = np.where(alpha > ALPHA_THRESHOLD)\n\n    mask_pixels = int(len(xs))\n    total_pixels = int(alpha.shape[0] * alpha.shape[1])\n    coverage = float(mask_pixels / total_pixels) if total_pixels else 0.0\n\n    alpha_pil = Image.fromarray(alpha)\n    _save_debug_pil("10_rembg_alpha_mask.png", alpha_pil, diagnostics)\n\n    _checkpoint(\n        "rembg_alpha_mask",\n        diagnostics,\n        mask_pixels=mask_pixels,\n        total_pixels=total_pixels,\n        coverage=coverage,\n        threshold=ALPHA_THRESHOLD,\n    )\n\n    if mask_pixels == 0:\n        return None, "rembg_empty_alpha_mask"\n\n    x0, x1 = int(xs.min()), int(xs.max())\n    y0, y1 = int(ys.min()), int(ys.max())\n\n    width, height = rgba.size\n    box_w = x1 - x0 + 1\n    box_h = y1 - y0 + 1\n\n    _checkpoint(\n        "rembg_bbox_raw",\n        diagnostics,\n        image_size=[width, height],\n        bbox=[x0, y0, x1, y1],\n        bbox_size=[box_w, box_h],\n        bbox_area_ratio=float((box_w * box_h) / (width * height)) if width and height else None,\n    )\n\n    if box_w < 120 or box_h < 180:\n        return None, "rembg_mask_too_small"\n\n    pad = max(16, int(min(box_w, box_h) * 0.04))\n    x0 = max(0, x0 - pad)\n    y0 = max(0, y0 - pad)\n    x1 = min(width - 1, x1 + pad)\n    y1 = min(height - 1, y1 + pad)\n\n    white = Image.new("RGBA", rgba.size, (255, 255, 255, 255))\n    composed = Image.alpha_composite(white, rgba)\n    _save_debug_pil("11_rembg_composited_full.png", composed.convert("RGB"), diagnostics)\n\n    cropped = composed.crop((x0, y0, x1 + 1, y1 + 1)).convert("RGB")\n    _save_debug_pil("12_rembg_cropped.png", cropped, diagnostics)\n\n    _checkpoint(\n        "rembg_crop",\n        diagnostics,\n        padded_bbox=[x0, y0, x1, y1],\n        cropped_size=[cropped.width, cropped.height],\n        crop_reduces_image=(cropped.width < width or cropped.height < height),\n    )\n\n    bgr = _pil_rgb_to_bgr(cropped)\n    if bgr is None:\n        return None, "rembg_bgr_conversion_failed"\n\n    _save_debug_cv("13_rembg_cropped_bgr.png", bgr, diagnostics)\n    return bgr, None\n\n\ndef _order_points(points):\n    rect = np.zeros((4, 2), dtype="float32")\n    s = points.sum(axis=1)\n    rect[0] = points[np.argmin(s)]\n    rect[2] = points[np.argmax(s)]\n    diff = np.diff(points, axis=1)\n    rect[1] = points[np.argmin(diff)]\n    rect[3] = points[np.argmax(diff)]\n    return rect\n\n\ndef _four_point_warp(image, points, diagnostics: dict[str, Any]):\n    rect = _order_points(points.astype("float32"))\n    tl, tr, br, bl = rect\n\n    width_a = np.linalg.norm(br - bl)\n    width_b = np.linalg.norm(tr - tl)\n    max_width = int(max(width_a, width_b))\n\n    height_a = np.linalg.norm(tr - br)\n    height_b = np.linalg.norm(tl - bl)\n    max_height = int(max(height_a, height_b))\n\n    _checkpoint("warp_dimensions", diagnostics, max_width=max_width, max_height=max_height)\n\n    if max_width < 160 or max_height < 260:\n        return None\n\n    dst = np.array(\n        [[0, 0], [max_width - 1, 0], [max_width - 1, max_height - 1], [0, max_height - 1]],\n        dtype="float32",\n    )\n\n    matrix = cv2.getPerspectiveTransform(rect, dst)\n    warped = cv2.warpPerspective(image, matrix, (max_width, max_height), borderMode=cv2.BORDER_REPLICATE)\n\n    if warped.shape[1] > warped.shape[0]:\n        warped = cv2.rotate(warped, cv2.ROTATE_90_COUNTERCLOCKWISE)\n        _checkpoint("warp_orientation", diagnostics, rotated_counterclockwise=True)\n    else:\n        _checkpoint("warp_orientation", diagnostics, rotated_counterclockwise=False)\n\n    _save_debug_cv("30_perspective_warped.png", warped, diagnostics)\n    return warped\n\n\ndef _find_document_quadrilateral(image, diagnostics: dict[str, Any]):\n    height, width = image.shape[:2]\n    image_area = float(height * width)\n\n    ratio = height / 900.0 if height > 900 else 1.0\n    small = cv2.resize(image, (int(width / ratio), int(height / ratio)))\n\n    gray = cv2.cvtColor(small, cv2.COLOR_BGR2GRAY)\n    gray = cv2.bilateralFilter(gray, 9, 75, 75)\n\n    edges = cv2.Canny(gray, 35, 110)\n    edges = cv2.dilate(edges, np.ones((5, 5), np.uint8), iterations=2)\n    edges = cv2.morphologyEx(edges, cv2.MORPH_CLOSE, np.ones((9, 9), np.uint8), iterations=2)\n    _save_debug_cv("20_edges.png", edges, diagnostics)\n\n    contours, _ = cv2.findContours(edges, cv2.RETR_EXTERNAL, cv2.CHAIN_APPROX_SIMPLE)\n    contours = sorted(contours, key=cv2.contourArea, reverse=True)[:30]\n\n    _checkpoint("contours_found", diagnostics, count=len(contours), image_size=[width, height])\n\n    best_quad = None\n    best_score = 0.0\n\n    for contour in contours:\n        area_small = float(cv2.contourArea(contour))\n        area = area_small * (ratio ** 2)\n        if image_area <= 0 or (area / image_area) < MIN_DOCUMENT_AREA_RATIO:\n            continue\n\n        perimeter = cv2.arcLength(contour, True)\n        for epsilon in (0.015, 0.02, 0.03, 0.04, 0.06, 0.08):\n            approx = cv2.approxPolyDP(contour, epsilon * perimeter, True)\n            if len(approx) != 4:\n                continue\n\n            quad = approx.reshape(4, 2).astype("float32") * ratio\n            x, y, w, h = cv2.boundingRect(quad.astype("int32"))\n            aspect = max(w, h) / max(1, min(w, h))\n            rect_area = float(w * h)\n            fill = area / rect_area if rect_area else 0.0\n            score = area * max(0.2, min(fill, 1.0))\n\n            if w >= 160 and h >= 260 and aspect >= 1.45 and score > best_score:\n                best_quad = quad\n                best_score = score\n\n    if best_quad is not None:\n        _checkpoint("strict_quad_selected", diagnostics, score=best_score, points=best_quad.astype(int).tolist())\n        return best_quad\n\n    joined = cv2.dilate(edges, np.ones((23, 23), np.uint8), iterations=2)\n    joined = cv2.morphologyEx(joined, cv2.MORPH_CLOSE, np.ones((31, 31), np.uint8), iterations=2)\n    _save_debug_cv("21_joined_edges.png", joined, diagnostics)\n\n    relaxed_contours, _ = cv2.findContours(joined, cv2.RETR_EXTERNAL, cv2.CHAIN_APPROX_SIMPLE)\n    relaxed_contours = sorted(relaxed_contours, key=cv2.contourArea, reverse=True)[:10]\n\n    best_box = None\n    best_relaxed_score = 0.0\n    rejected: list[dict[str, Any]] = []\n\n    for contour in relaxed_contours:\n        area_small = float(cv2.contourArea(contour))\n        area = area_small * (ratio ** 2)\n        if image_area <= 0:\n            continue\n\n        rect = cv2.minAreaRect(contour)\n        box_small = cv2.boxPoints(rect).astype("float32")\n        box = box_small * ratio\n\n        x, y, w, h = cv2.boundingRect(box.astype("int32"))\n        aspect = max(w, h) / max(1, min(w, h))\n        box_ratio = float(w * h) / image_area if image_area else 0.0\n        area_ratio = area / image_area if image_area else 0.0\n\n        candidate = {\n            "w": int(w),\n            "h": int(h),\n            "aspect": float(aspect),\n            "box_ratio": float(box_ratio),\n            "area_ratio": float(area_ratio),\n        }\n\n        if area_ratio < MIN_DOCUMENT_AREA_RATIO:\n            candidate["reject"] = "area_ratio_too_small"\n            rejected.append(candidate)\n            continue\n        if w < 160 or h < 260:\n            candidate["reject"] = "box_too_small"\n            rejected.append(candidate)\n            continue\n        if aspect < 1.35:\n            candidate["reject"] = "aspect_too_low"\n            rejected.append(candidate)\n            continue\n        if box_ratio < 0.04 or box_ratio > 0.98:\n            candidate["reject"] = "box_ratio_out_of_range"\n            rejected.append(candidate)\n            continue\n\n        score = area * aspect\n        if score > best_relaxed_score:\n            best_box = box\n            best_relaxed_score = score\n\n    diagnostics["relaxed_rejected_candidates"] = rejected[:10]\n\n    if best_box is not None:\n        _checkpoint("relaxed_box_selected", diagnostics, score=best_relaxed_score, points=best_box.astype(int).tolist())\n        return best_box\n\n    _checkpoint("no_quad_selected", diagnostics)\n    return None\n\n\ndef _remove_background_by_document_edges(image, diagnostics: dict[str, Any]):\n    if cv2 is None or np is None:\n        return image, False\n\n    quad = _find_document_quadrilateral(image, diagnostics)\n    if quad is None:\n        return image, False\n\n    warped = _four_point_warp(image, quad, diagnostics)\n    if warped is None:\n        return image, False\n\n    return warped, True\n\n\ndef apply_receipt_image_preprocessing(file_bytes: bytes, filename: str) -> tuple[bytes, ReceiptImagePreprocessingDecision]:\n    diagnostics: dict[str, Any] = {"filename": filename}\n    suffix = Path(filename or "").suffix.lower()\n\n    if suffix and suffix not in IMAGE_SUFFIXES:\n        return file_bytes, ReceiptImagePreprocessingDecision(\n            "receipt_image_preprocessing",\n            "original",\n            [],\n            ["unsupported_image_suffix"],\n            None,\n            diagnostics,\n        )\n\n    applied_steps: list[str] = []\n    fallback_reason: list[str] = []\n\n    original_cv = _decode_image(file_bytes)\n    if original_cv is not None:\n        _checkpoint("original_decoded", diagnostics, size=[original_cv.shape[1], original_cv.shape[0]])\n\n    image, ai_reason = _remove_background_with_rembg(file_bytes, diagnostics)\n    if image is not None:\n        applied_steps.append("ai_background_removed")\n    elif ai_reason:\n        fallback_reason.append(ai_reason)\n\n    if image is None:\n        image = original_cv\n\n    if image is None:\n        return file_bytes, ReceiptImagePreprocessingDecision(\n            "receipt_image_preprocessing",\n            "original",\n            [],\n            fallback_reason + ["image_decode_failed_or_cv2_unavailable"],\n            None,\n            diagnostics,\n        )\n\n    before_geometry = image.copy()\n    image, document_extracted = _remove_background_by_document_edges(image, diagnostics)\n    if document_extracted:\n        applied_steps.append("document_edge_background_removed")\n\n    diff_original = _image_difference_ratio(original_cv, image)\n    diff_before_geometry = _image_difference_ratio(before_geometry, image)\n    diagnostics["difference_ratio_vs_original"] = diff_original\n    diagnostics["difference_ratio_vs_before_geometry"] = diff_before_geometry\n    diagnostics["final_size"] = [image.shape[1], image.shape[0]] if hasattr(image, "shape") else None\n\n    _save_debug_cv("40_final_runtime_preprocessed.png", image, diagnostics)\n\n    output = _encode_image_png(image)\n    if not output:\n        return file_bytes, ReceiptImagePreprocessingDecision(\n            "receipt_image_preprocessing",\n            "original",\n            applied_steps,\n            fallback_reason + ["output_encode_failed"],\n            None,\n            diagnostics,\n        )\n\n    # Diagnostic only: do not hard-fail production yet. We expose the risk explicitly.\n    if diff_original is not None and diff_original < 0.01:\n        fallback_reason.append("final_output_nearly_identical_to_original")\n\n    route = "original" if not applied_steps else "+".join(applied_steps)\n    return output, ReceiptImagePreprocessingDecision(\n        "receipt_image_preprocessing",\n        route,\n        applied_steps,\n        fallback_reason,\n        None,\n        diagnostics,\n    )\n', encoding="utf-8")

